class Solution:
    def countSubIslands(self, grid1, grid2):
        m = len(grid2)
        n = len(grid2[0])
        seen = [[False] * n for _ in range(m)]
        count = 0
        for i in range(m):
            for j in range(n):
                if grid2[i][j] == 1 and not seen[i][j]:
                    stack = [(i, j)]
                    seen[i][j] = True
                    ok = True
                    while stack:
                        r, c = stack.pop()
                        if grid1[r][c] == 0:
                            ok = False
                        for dr, dc in ((1,0),(-1,0),(0,1),(0,-1)):
                            nr, nc = r + dr, c + dc
                            if 0 <= nr < m and 0 <= nc < n and grid2[nr][nc] == 1 and not seen[nr][nc]:
                                seen[nr][nc] = True
                                stack.append((nr, nc))
                    if ok:
                        count += 1
        return count

